solution_code:
#include <array>
#include <iostream>

int countAbove(std::array<int, 5> arr, int threshold) {
    int count = 0;
    for (std::size_t i = 0; i < arr.size(); ++i) {
        if (arr[i] > threshold) {
            ++count;
        }
    }
    return count;
}

int main() {
    std::array<int, 5> nums {};
    for (std::size_t i = 0; i < nums.size(); ++i) {
        std::cin >> nums[i];
    }
    int threshold {};
    std::cin >> threshold;
    std::cout << "Count: " << countAbove(nums, threshold) << '\n';
    return 0;
}
